#include "mix_kernels_cpu.h"

namespace {

constexpr int ELEMENTS_PER_THREAD = 8;
constexpr int FUSION_DEGREE = 4;
constexpr int BLOCK_SIZE = 256;

struct half2 {
  uint16_t x;
  uint16_t y;
};

volatile double g_sink_double = 0.0;

template <typename T>
inline double to_double(T v) {
  return static_cast<double>(v);
}

template <>
inline double to_double<short>(short v) {
  return static_cast<double>(static_cast<int>(v));
}

template <>
inline double to_double<int>(int v) {
  return static_cast<double>(v);
}

template <typename T>
inline T recurrence_zero(T seed, unsigned int compute_iterations) {
  T x = static_cast<T>(0);
  for (unsigned int i = 0; i < compute_iterations; ++i) {
    x = x * x + seed;
  }
  return x;
}

template <>
inline int recurrence_zero<int>(int seed, unsigned int compute_iterations) {
  uint32_t x = 0;
  const uint32_t s = static_cast<uint32_t>(seed);
  for (unsigned int i = 0; i < compute_iterations; ++i) {
    x = x * x + s;
  }
  return static_cast<int32_t>(x);
}

template <>
inline short recurrence_zero<short>(short seed, unsigned int compute_iterations) {
  uint16_t x = 0;
  const uint16_t s = static_cast<uint16_t>(seed);
  for (unsigned int i = 0; i < compute_iterations; ++i) {
    x = static_cast<uint16_t>(x * x + s);
  }
  return static_cast<int16_t>(x);
}

template <typename T>
double benchmark_scan(T* g_data, long size, unsigned int compute_iterations, T seed) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const long total_threads = compute_grid_size;
  const long big_stride = total_threads * ELEMENTS_PER_THREAD;

  double checksum = to_double(recurrence_zero<T>(seed, compute_iterations));

  const double start = omp_get_wtime();

#pragma omp parallel for schedule(static) reduction(+ : checksum)
  for (long linear_tid = 0; linear_tid < total_threads; ++linear_tid) {
    const long block_idx = linear_tid / BLOCK_SIZE;
    const int thread_idx = static_cast<int>(linear_tid % BLOCK_SIZE);
    const long idx = block_idx * BLOCK_SIZE * ELEMENTS_PER_THREAD + thread_idx;

    for (int k = 0; k < FUSION_DEGREE; ++k) {
#pragma omp simd reduction(+ : checksum)
      for (int j = 0; j < ELEMENTS_PER_THREAD; ++j) {
        checksum += static_cast<double>(g_data[idx + j * BLOCK_SIZE + k * big_stride]);
      }
    }
  }

  const double elapsed_ms = (omp_get_wtime() - start) * 1000.0;
  g_sink_double += checksum;
  return elapsed_ms;
}

void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / ELEMENTS_PER_THREAD / 128;
  const long total_reduced_blocks = reduced_grid_size / BLOCK_SIZE;
  const long total_threads = total_reduced_blocks * BLOCK_SIZE;
  const long big_stride = total_threads * ELEMENTS_PER_THREAD;
  short* data = reinterpret_cast<short*>(cd);

  double checksum = 0.0;

#pragma omp parallel for schedule(static) reduction(+ : checksum)
  for (long linear_tid = 0; linear_tid < total_threads; ++linear_tid) {
    const long block_idx = linear_tid / BLOCK_SIZE;
    const int thread_idx = static_cast<int>(linear_tid % BLOCK_SIZE);
    const long idx = block_idx * BLOCK_SIZE * ELEMENTS_PER_THREAD + thread_idx;

    for (int k = 0; k < FUSION_DEGREE; ++k) {
#pragma omp simd reduction(+ : checksum)
      for (int j = 0; j < ELEMENTS_PER_THREAD; ++j) {
        checksum += static_cast<double>(data[idx + j * BLOCK_SIZE + k * big_stride]);
      }
    }
  }

  g_sink_double += checksum;
}

void runbench(double* cd, long size, bool doHalfs, unsigned int compute_iterations) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const long long computations =
      (ELEMENTS_PER_THREAD * static_cast<long long>(compute_grid_size) +
       (2LL * ELEMENTS_PER_THREAD * static_cast<long long>(compute_iterations)) *
           static_cast<long long>(compute_grid_size)) *
      FUSION_DEGREE;
  const long long memoryoperations = size;

  const float kernel_time_mad_sp =
      static_cast<float>(benchmark_scan<float>(reinterpret_cast<float*>(cd), size,
                                               compute_iterations, 1.0f));

  const float kernel_time_mad_dp =
      static_cast<float>(benchmark_scan<double>(cd, size, compute_iterations, 1.0));

  float kernel_time_mad_hp = 0.0f;
  if (doHalfs) {
    kernel_time_mad_hp = 0.0f;
  }

  const float kernel_time_mad_int =
      static_cast<float>(benchmark_scan<int>(reinterpret_cast<int*>(cd), size,
                                             compute_iterations, 1));

  std::printf(
      "         %4u,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      static_cast<double>(computations) /
          (static_cast<double>(memoryoperations) * sizeof(float)),
      kernel_time_mad_sp,
      static_cast<double>(computations) / kernel_time_mad_sp * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(float)) / kernel_time_mad_sp *
          1000.0 / (1000.0 * 1000.0 * 1000.0),
      static_cast<double>(computations) /
          (static_cast<double>(memoryoperations) * sizeof(double)),
      kernel_time_mad_dp,
      static_cast<double>(computations) / kernel_time_mad_dp * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(double)) / kernel_time_mad_dp *
          1000.0 / (1000.0 * 1000.0 * 1000.0),
      static_cast<double>(2 * computations) /
          (static_cast<double>(memoryoperations) * sizeof(half2)),
      kernel_time_mad_hp,
      static_cast<double>(2 * computations) / kernel_time_mad_hp * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(half2)) / kernel_time_mad_hp *
          1000.0 / (1000.0 * 1000.0 * 1000.0),
      static_cast<double>(computations) /
          (static_cast<double>(memoryoperations) * sizeof(int)),
      kernel_time_mad_int,
      static_cast<double>(computations) / kernel_time_mad_int * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(int)) / kernel_time_mad_int *
          1000.0 / (1000.0 * 1000.0 * 1000.0));
}

}  // namespace

void mixbenchCPU(void* c, size_t size_bytes) {
