  std::printf("Trade-off type:       %s\n", benchtype);
  std::printf("Elements per thread:  %d\n", ELEMENTS_PER_THREAD);
  std::printf("Thread fusion degree: %d\n", FUSION_DEGREE);

  const bool doHalfs = false;
  if (!doHalfs) {
    std::printf(
        "Warning:              Half precision computations are not supported\n");
  }

  double* cd = static_cast<double*>(std::malloc(size_bytes));
  if (cd == nullptr) {
    std::fprintf(stderr, "Allocation failed\n");
    std::exit(EXIT_FAILURE);
  }

  std::memset(cd, 0, size_bytes);

  std::printf(
      "----------------------------------------------------------------------------- CSV data "
      "-----------------------------------------------------------------------------\n");
  std::printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
