      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  "
      "GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
      "GIOPS, GB/sec\n");

  runbench_warmup(cd, size);

  runbench(cd, size, doHalfs, 0);
  runbench(cd, size, doHalfs, 1);
  runbench(cd, size, doHalfs, 2);
  runbench(cd, size, doHalfs, 3);
  runbench(cd, size, doHalfs, 4);
  runbench(cd, size, doHalfs, 5);
  runbench(cd, size, doHalfs, 6);
  runbench(cd, size, doHalfs, 7);
  runbench(cd, size, doHalfs, 8);
  runbench(cd, size, doHalfs, 9);
  runbench(cd, size, doHalfs, 10);
  runbench(cd, size, doHalfs, 11);
  runbench(cd, size, doHalfs, 12);
  runbench(cd, size, doHalfs, 13);
  runbench(cd, size, doHalfs, 14);
  runbench(cd, size, doHalfs, 15);
  runbench(cd, size, doHalfs, 16);
  runbench(cd, size, doHalfs, 17);
  runbench(cd, size, doHalfs, 18);
  runbench(cd, size, doHalfs, 20);
  runbench(cd, size, doHalfs, 22);
  runbench(cd, size, doHalfs, 24);
  runbench(cd, size, doHalfs, 28);
  runbench(cd, size, doHalfs, 32);
  runbench(cd, size, doHalfs, 40);
