  runbench(cd, size, doHalfs, 512);
  runbench(cd, size, doHalfs, 1024);

  std::printf(
      "--------------------------------------------------------------------------------------------------------------------------------------------------------------------\n");

  std::memcpy(c, cd, size_bytes);
  std::free(cd);
}
